    customIcon: z.string().optional(),
    align: z.enum(['left', 'center', 'right']).optional().default('left'),
    fontSize: z.number().optional(),
    color: z.string().optional(),
    letterSpacing: z.number().optional(),
    lineHeight: z.number().optional(),
    textAlign: z.enum(['left', 'center', 'right']).optional(),
    fontVariant: z.enum(['padrão', 'destaque']).optional().default('padrão'),
    handle: z.string().optional(),
    avatar: z.string().optional(),
    handleColor: z.string().optional(),
    hideName: z.boolean().optional().default(false),
    padding: z.number().optional(),
  }).optional().default({}),
});

export const imageConfigSchema = z.object({
  type: z.enum(['IMAGE_SELECT', 'IMAGE_BACKGROUND', 'IMAGE_BOX', 'FOCUS_SUBJECT', 'IMAGE_GLASS_CARD', 'IMAGE_SPLIT_HALF', 'NONE']).optional().default('NONE'),
  url: z.string().optional(),
  overlay: z.enum(['dark', 'blur-card', 'none']).optional().default('none'),
  boxOverlay: z.enum(['dark', 'light']).optional().default('dark'),
  position: z.enum(['right', 'left', 'top', 'bottom']).optional().default('right'),
  format: z.enum(['png', 'jpg']).optional().default('jpg'),

  // Outer Box Transforms
  boxRotation: z.number().optional().default(0),
  boxScale: z.number().optional().default(1),
  boxX: z.number().optional().default(0),
  boxY: z.number().optional().default(0),
  width: z.number().optional().default(480),

  // Inner Image Transforms
  imageRotation: z.number().optional().default(0),
  imageScale: z.number().optional().default(1),
  imageX: z.number().optional().default(0),
  imageY: z.number().optional().default(0),

  backgroundOpacity: z.number().min(0).max(1).optional().default(1),
