const SafeTextArea = ({ value, onChange, className, placeholder }: { value: string, onChange: (val: string) => void, className?: string, placeholder?: string }) => {
  const [localValue, setLocalValue] = useState(value);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  useEffect(() => { if (value !== localValue) setLocalValue(value); }, [value]);
  const handleChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const val = e.target.value;
    setLocalValue(val);
    onChange(val);
  };
  return <textarea ref={textareaRef} value={localValue} onChange={handleChange} className={className} placeholder={placeholder} />;
};

