  const bgImageInputRef = useRef<HTMLInputElement>(null);
  const activePaletteColors = useMemo(() => brandPresets.find(p => p.id === activePaletteId)?.colors || [], [brandPresets, activePaletteId]);

  const showToast = useCallback((message: string, type: 'success' | 'error' = 'success') => { setToast({ message, type }); setTimeout(() => setToast(null), 3000); }, []);

  const updateSlideProperties = useCallback((updates: { path: (string | number)[], value: any }[]) => {
    setDslInput(prev => {
      try {
        const parsed = JSON.parse(prev);
        if (!parsed.slides[currentIndex]) return prev;
        updates.forEach(({ path, value }) => {
          let target = parsed.slides[currentIndex];
          for (let i = 0; i < path.length - 1; i++) {
            const key = path[i];
            if (!target[key] || typeof target[key] !== 'object') target[key] = {};
            target = target[key];
          }
          target[path[path.length - 1]] = value;
        });
        return JSON.stringify(parsed, null, 2);
      } catch (e) { return prev; }
    });
  }, [currentIndex]);

  const updateGlobalProperty = useCallback((path: (string | number)[], value: any) => {
    setDslInput(prev => {
      try {
        const parsed = JSON.parse(prev);
        let target = parsed;
        for (let i = 0; i < path.length - 1; i++) {
          const key = path[i];
          if (!target[key] || typeof target[key] !== 'object') target[key] = {};
          target = target[key];
        }
        target[path[path.length - 1]] = value;
        return JSON.stringify(parsed, null, 2);
      } catch (e) { return prev; }
    });
  }, []);

  const updateSlideProperty = useCallback((path: (string | number)[], value: any) => updateSlideProperties([{ path, value }]), [updateSlideProperties]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]; if (!file) return;
    const reader = new FileReader();
    reader.onloadend = () => updateSlideProperty(['image', 'url'], reader.result as string);
    reader.readAsDataURL(file);
  };

  const handleBgImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]; if (!file) return;
    const reader = new FileReader();
    reader.onloadend = () => { const imgUrl = reader.result as string; updateSlideProperty(['options', 'backgroundImage'], imgUrl); setUploadedBackgrounds(prev => [...new Set([...prev, imgUrl])]); showToast("Imagem de fundo aplicada!"); };
    reader.readAsDataURL(file);
  };

  const handleFontUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]; if (!file) return;
    setIsUploadingFont(true);
    try {
      const sanitizedName = file.name.replace(/\s+/g, '_').replace(/[^a-zA-Z0-9._-]/g, '');
      const fileName = `${Date.now()}_${sanitizedName}`;
      const { data, error } = await supabase.storage.from('fonts').upload(fileName, file);
      if (error) throw error;
      const { data: { publicUrl } } = supabase.storage.from('fonts').getPublicUrl(data.path);
      const newFont: CustomFont = { id: crypto.randomUUID(), name: file.name.split('.')[0], family: sanitizedName.split('.')[0].replace(/[^a-zA-Z0-9]/g, ''), url: publicUrl };
      updateGlobalProperty(['customFonts'], [...(carousel?.customFonts || []), newFont]);
      showToast("Fonte sincronizada!");
    } catch (err: any) { showToast("Erro ao subir fonte.", "error"); } finally { setIsUploadingFont(false); if (fontInputRef.current) fontInputRef.current.value = ''; }
  };

  const handleImportProject = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        try { const content = event.target?.result as string; JSON.parse(content); setDslInput(content); showToast("Projeto importado!"); } catch (err) { showToast("JSON inválido.", "error"); }
      };
      reader.readAsText(file);
    }
  };

  const loadData = useCallback(async () => {
    setIsSyncing(true);
    try { const { data: palettes } = await supabase.from('brand_palettes').select('*'); if (palettes) setBrandPresets([...DEFAULT_BRAND_PRESETS, ...palettes]); } 
    catch (err: any) { console.error("Load failed", err); } finally { setIsSyncing(false); }
  }, []);
  useEffect(() => { loadData(); }, [loadData]);

  const handleRender = useCallback(() => {
    try {
      const parsed = JSON.parse(dslInput);
      const result = carouselSchema.safeParse(parsed);
      if (result.success) { setCarousel(result.data); setError(null); } 
      else { 
        setError(result.error.issues.map(e => `[${e.path.join(' → ')}]: ${e.message}`).join('\n'));
        // Fallback: Tenta usar os dados brutos se possível, ou mantém o carrossel anterior mas avisa do erro
        if (!carousel) setCarousel(parsed as any);
      }
    } catch (e: any) { setError(`Sintaxe: ${e.message}`); }
  }, [dslInput]);
  useEffect(() => { handleRender(); }, [handleRender]);

  const startBatchExport = async () => {
    if (!carousel || !canvasRef.current || isExporting) return;
    setShowExportModal(false);
    const originalIndex = currentIndex;
    const exportIndices = Array.from(selectedSlidesToExport).sort((a, b) => Number(a) - Number(b));
    const images: { name: string; dataUrl: string }[] = [];
    setIsExporting(true);
    try {
      for (let i = 0; i < exportIndices.length; i++) {
        setExportStatus(`Renderizando: ${i + 1}/${exportIndices.length}`);
        setExportProgress(Math.round(((i + 1) / exportIndices.length) * 100));
        setCurrentIndex(exportIndices[i]);
        await new Promise(resolve => setTimeout(resolve, 800));
        const dataUrl = await captureJpeg(canvasRef.current);
        images.push({ name: `slide-${(i + 1).toString().padStart(2, '0')}.jpg`, dataUrl });
      }
      await downloadZip(images, `impact-${Date.now()}.zip`, dslInput);
      setIsExporting(false); setCurrentIndex(originalIndex);
    } catch (err) { setIsExporting(false); setCurrentIndex(originalIndex); }
  };

  const handleApplyPalettePreset = (preset: any) => {
    setActivePaletteId(preset.id);
    const defs = preset.defaults || { bg: preset.colors[0], accent: preset.colors[2], text: preset.colors[1], cardBg: preset.colors[2] };
    updateSlideProperties([{ path: ['options', 'background'], value: defs.bg }, { path: ['options', 'accent'], value: defs.accent }, { path: ['options', 'text'], value: defs.text }, { path: ['options', 'cardBg'], value: defs.cardBg }, { path: ['options', 'fontPadrão'], value: preset.font_padrao || 'Inter' }, { path: ['options', 'fontDestaque'], value: preset.font_destaque || 'Instrument Serif' }]);
  };

  const allFontOptions = useMemo(() => [...GOOGLE_FONTS, ...(carousel?.customFonts || []).map(f => ({ id: f.family, label: `${f.name} (Custom)` }))], [carousel?.customFonts]);

  return (
    <div className="flex h-screen w-full bg-[#050507] text-zinc-300 font-sans overflow-hidden relative" onDragOver={e => e.preventDefault()} onDrop={e => { e.preventDefault(); const f = e.dataTransfer.files[0]; if (f) { const r = new FileReader(); r.onload = ev => setDslInput(ev.target?.result as string); r.readAsText(f); } }}>
      {toast && <div className={`fixed bottom-12 left-1/2 -translate-x-1/2 z-[9999] px-12 py-6 rounded-[32px] flex items-center gap-6 animate-in slide-in-from-bottom-12 fade-in duration-500 shadow-2xl backdrop-blur-3xl border border-white/10 ${toast.type === 'success' ? 'bg-brand/95 text-black' : 'bg-red-500/95 text-white'}`}><CheckCircle size={28} /> <span className="text-[16px] font-black uppercase">{toast.message}</span></div>}
      <input type="file" ref={importInputRef} onChange={handleImportProject} accept=".json" className="hidden" />
      <input type="file" ref={fontInputRef} onChange={handleFontUpload} accept=".ttf,.otf,.woff2" className="hidden" />
      <input type="file" ref={bgImageInputRef} onChange={handleBgImageUpload} accept="image/*" className="hidden" />
      {toolbarState && <FloatingTextToolbar state={toolbarState} onClose={() => setToolbarState(null)} onUpdate={updateSlideProperties} />}
      {showExportModal && <div className="fixed inset-0 z-[300] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl animate-in fade-in" onClick={() => setShowExportModal(false)}><div className="w-full max-w-2xl bg-zinc-900 border border-white/10 rounded-[40px] p-10 space-y-8 shadow-2xl" onClick={e => e.stopPropagation()}><div className="flex items-center justify-between"><div><h2 className="text-xl font-black text-white uppercase italic">Exportar</h2></div><button onClick={() => setShowExportModal(false)} className="p-3 text-zinc-500"><X/></button></div><div className="grid grid-cols-4 gap-4 max-h-[400px] overflow-y-auto custom-scrollbar">{carousel?.slides.map((s, idx) => (<button key={idx} onClick={() => { const next = new Set(selectedSlidesToExport); if (next.has(idx)) next.delete(idx); else next.add(idx); setSelectedSlidesToExport(next); }} className={`relative aspect-[4/5] rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-3 ${selectedSlidesToExport.has(idx) ? 'border-brand bg-brand/10' : 'border-white/5 bg-black/40'}`}><div className={`w-10 h-10 rounded-full flex items-center justify-center ${selectedSlidesToExport.has(idx) ? 'bg-brand text-black' : 'bg-zinc-800'}`}>{idx + 1}</div>{selectedSlidesToExport.has(idx) && <CheckCircle2 className="absolute top-2 right-2 text-brand" size={16} />}</button>))}</div><div className="flex gap-4 pt-4 border-t border-white/5"><button onClick={() => setSelectedSlidesToExport(new Set())} className="px-6 py-5 text-[10px] font-black text-zinc-500 uppercase">Limpar</button><button onClick={() => setSelectedSlidesToExport(new Set(carousel?.slides.map((_, i) => i)))} className="px-6 py-5 text-[10px] font-black text-brand uppercase">Todos</button><button onClick={startBatchExport} className="flex-1 py-5 bg-brand text-black font-black uppercase rounded-2xl">Gerar {selectedSlidesToExport.size} Slides</button></div></div></div>}

      <div className="flex h-screen w-full">
        <aside className="w-[440px] border-r border-white/5 flex flex-col bg-zinc-900/50 backdrop-blur-2xl z-20 shrink-0">
          <header className="p-5 border-b border-white/5 flex flex-col gap-4">
            <div className="flex items-center justify-between"><button onClick={() => importInputRef.current?.click()} className="p-2 bg-white/5 rounded-lg text-zinc-500"><Upload size={18} /></button><img src={LOGO_URL} className="h-8 object-contain" /><div className="w-9" /></div>
            <nav className="flex gap-1 p-1 bg-black/40 rounded-xl">{[{ id: 'TEMPLATES', icon: Library }, { id: 'BLOCKS', icon: TypeIcon }, { id: 'DESIGN', icon: Palette }, { id: 'FX', icon: Sparkles }, { id: 'ASSETS', icon: ImageIcon }, { id: 'JSON', icon: FileJson }].map(tab => (<button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex-1 py-3 rounded-lg flex items-center justify-center ${activeTab === tab.id ? 'bg-zinc-800 text-brand' : 'text-zinc-500'}`}><tab.icon size={16} /></button>))}</nav>
          </header>
          <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-10">
            {activeTab === 'DESIGN' ? (
              <div className="space-y-10 animate-in slide-in-from-left-4">
                <section className="space-y-5"><div className="flex items-center justify-between"><div className="flex items-center gap-2.5"><Palette size={16} className="text-brand" /><h3 className="text-[10px] font-black text-zinc-100 uppercase tracking-[0.2em]">Branding</h3></div></div><div className="grid grid-cols-1 gap-2.5">{brandPresets.map(p => (<button key={p.id} onClick={() => handleApplyPalettePreset(p)} className={`w-full p-4 border rounded-[22px] flex items-center justify-between transition-all ${activePaletteId === p.id ? 'bg-brand/10 border-brand' : 'bg-white/5 border-white/5'}`}><div className="flex items-center gap-4"><div className="flex -space-x-1.5">{p.colors.slice(0, 3).map((c: any, i: any) => (<div key={i} className="w-5 h-5 rounded-full border-2 border-zinc-950" style={{ backgroundColor: c }} />))}</div><span className={`text-[11px] font-black uppercase ${activePaletteId === p.id ? 'text-brand' : 'text-zinc-500'}`}>{p.name}</span></div></button>))}</div></section>
                <section className="space-y-8 pt-6 border-t border-white/5"><div className="flex items-center gap-2.5"><Droplet size={16} className="text-brand" /><h3 className="text-[10px] font-black text-zinc-100 uppercase tracking-[0.2em]">Cores</h3></div><div className="space-y-6"><ColorPropertyControl label="Fundo" value={currentSlide?.options?.background || '#0D0D0D'} paletteColors={activePaletteColors} onChange={v => updateSlideProperty(['options', 'background'], v)} /><ColorPropertyControl label="Texto" value={currentSlide?.options?.text || '#FFFFFF'} paletteColors={activePaletteColors} onChange={v => updateSlideProperty(['options', 'text'], v)} /><ColorPropertyControl label="Accent" value={currentSlide?.options?.accent || '#1fb2f7'} paletteColors={activePaletteColors} onChange={v => updateSlideProperty(['options', 'accent'], v)} /></div></section>
                <section className="space-y-6 pt-6 border-t border-white/5"><div className="flex items-center gap-2.5"><Baseline size={16} className="text-brand" /><h3 className="text-[10px] font-black text-zinc-100 uppercase tracking-[0.2em]">Tipografia</h3></div><div className="grid grid-cols-1 gap-5"><div className="space-y-2"><label className="text-[9px] font-black uppercase text-zinc-500">Fonte Padrão</label><select value={currentSlide?.options?.fontPadrão || 'Inter'} onChange={e => updateSlideProperty(['options', 'fontPadrão'], e.target.value)} className="w-full bg-zinc-950/40 border border-white/5 rounded-2xl py-3.5 px-4 text-[11px] font-bold text-white outline-none">{allFontOptions.map(f => <option key={f.id} value={f.id}>{f.label}</option>)}</select></div></div></section>
              </div>
            ) : activeTab === 'BLOCKS' ? (
              <div className="space-y-6 animate-in slide-in-from-left-4">{carousel?.slides[currentIndex]?.blocks.map((block, bIdx) => (<div key={bIdx} className="bg-black/40 border border-white/5 rounded-[28px] overflow-hidden"><div className="px-6 py-4 bg-black/40 flex items-center justify-between border-b border-white/5"><span className="text-[10px] font-black uppercase text-zinc-400">{block.type}</span><button onClick={() => { const next = [...carousel.slides[currentIndex].blocks]; next.splice(bIdx, 1); updateSlideProperty(['blocks'], next); }} className="p-1.5 text-zinc-600 hover:text-red-400"><Trash2 size={14} /></button></div><div className="p-6">{block.type !== 'SPACER' && <SafeTextArea value={(Array.isArray(block.content) ? block.content.join('\n') : block.content as string) || ''} onChange={val => updateSlideProperty(['blocks', bIdx, 'content'], block.type === 'LIST' ? val.split('\n') : val)} className="w-full bg-black/60 border border-white/5 rounded-2xl p-5 text-[13px] font-medium text-white outline-none min-h-[120px]" />}</div></div>))}</div>
            ) : activeTab === 'ASSETS' ? (
              <div className="space-y-12 animate-in slide-in-from-left-4"><section className="space-y-6"><div className="flex items-center gap-2.5"><ImageIconLucide size={18} className="text-brand" /><h3 className="text-[11px] font-black text-zinc-100 uppercase tracking-[0.2em]">Imagem</h3></div><div className="relative aspect-video rounded-3xl overflow-hidden bg-zinc-950 border border-white/5 group">{imageConfig?.url ? <img src={imageConfig.url} className="w-full h-full object-contain" /> : <div className="w-full h-full flex items-center justify-center text-zinc-700"><Icons.ImagePlus size={40} /></div>}<input type="file" onChange={handleImageUpload} className="absolute inset-0 opacity-0 cursor-pointer" accept="image/*" /></div><div className="grid grid-cols-5 gap-2">{IMAGE_TYPE_PRESETS.map(p => (<button key={p.id} onClick={() => updateSlideProperty(['image', 'type'], p.id)} className={`p-3 rounded-xl border flex items-center justify-center ${imageConfig?.type === p.id ? 'bg-brand text-black' : 'bg-black/40 text-zinc-500'}`}><p.icon size={18}/></button>))}</div></section></div>
            ) : activeTab === 'JSON' ? (
              <textarea value={dslInput} onChange={e => setDslInput(e.target.value)} className="w-full h-[600px] bg-black/40 p-4 font-mono text-[10px] border border-white/5 rounded-2xl outline-none" spellCheck={false} />
            ) : (
              <div className="grid grid-cols-1 gap-2">{templates.map(tpl => (<button key={tpl.name} onClick={() => updateSlideProperty(['template'], tpl.name)} className={`w-full p-4 border rounded-2xl flex items-center gap-4 ${currentSlide?.template === tpl.name ? 'bg-brand/10 border-brand' : 'bg-white/5 border-white/5'}`}><Library size={18}/><div className="text-left"><p className={`text-[10px] font-black uppercase ${currentSlide?.template === tpl.name ? 'text-brand' : 'text-white'}`}>{tpl.name}</p></div></button>))}</div>
            )}
          </div>
          <footer className="p-5 border-t border-white/5 bg-zinc-950"><button onClick={() => { setSelectedSlidesToExport(new Set(carousel?.slides.map((_, i) => i))); setShowExportModal(true); }} className="w-full py-4 bg-brand text-black font-black rounded-xl text-[10px] uppercase flex items-center justify-center gap-3"><Download size={16} /> Exportar</button></footer>
        </aside>
        <main className="flex-1 bg-[#121214] relative flex flex-col">
          {error && <div className="absolute top-5 left-1/2 -translate-x-1/2 z-[500] bg-red-600 text-white px-8 py-4 rounded-full flex items-center gap-6 shadow-2xl animate-in slide-in-from-top-4 backdrop-blur-md"><AlertCircle size={20}/><div className="flex flex-col"><span className="text-[10px] font-black uppercase opacity-60">Erro de Estrutura</span><span className="text-[12px] font-bold font-mono truncate max-w-[400px]">{error.split('\n')[0]}</span></div><button onClick={() => setError(null)} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X size={18}/></button></div>}
          <div className="absolute left-6 top-1/2 -translate-y-1/2 z-40 flex flex-col items-center gap-4 bg-black/40 backdrop-blur-2xl p-3 rounded-[32px] border border-white/10 shadow-2xl"><button onClick={() => setZoom(Math.min(1.5, zoom + 0.05))} className="p-3 text-zinc-400 hover:text-brand"><ZoomIn size={20} /></button><div className="text-[10px] font-black font-mono text-zinc-500 py-1">{(zoom * 100).toFixed(0)}%</div><button onClick={() => setZoom(Math.max(0.1, zoom - 0.05))} className="p-3 text-zinc-400 hover:text-brand"><ZoomOut size={20} /></button></div>
          <div className="flex-1 flex items-center justify-center overflow-auto p-20" onMouseUp={e => {
            const s = window.getSelection(); if (!s || s.isCollapsed) return;
            const r = s.getRangeAt(0).getBoundingClientRect();
            const tb = (e.target as HTMLElement).closest('[data-block-index]');
            if (tb && carousel?.slides[currentIndex]) {
              const idx = parseInt(tb.getAttribute('data-block-index') || '0');
              const blk = carousel.slides[currentIndex].blocks[idx];
              if (blk) setToolbarState({ x: r.left + r.width/2, y: r.top, blockIndex: idx, blockType: blk.type, options: blk.options || {}, content: blk.content || '' });
            }
          }}><div style={{ transform: `scale(${zoom})`, transformOrigin: 'center' }} className="transition-transform duration-500 shadow-2xl shrink-0">{carousel?.slides?.[currentIndex] ? <SlideCanvas slide={carousel.slides[currentIndex]} index={currentIndex} canvasRef={canvasRef} onEditIcon={(b, i) => setEditingIconBlock({ block: b, index: i })} customFonts={carousel.customFonts} /> : <div className="w-[1080px] h-[1350px] bg-zinc-900 flex items-center justify-center text-zinc-600 font-black text-4xl italic uppercase tracking-tighter">Erro de Renderização</div>}</div></div>
          {carousel && carousel.slides.length > 0 && (<div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-40 flex items-center gap-6 bg-black/50 backdrop-blur-2xl px-8 py-4 rounded-full border border-white/5"><button disabled={currentIndex === 0} onClick={() => setCurrentIndex(prev => prev - 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5"><ChevronLeft size={20}/></button><div className="flex gap-2.5">{carousel.slides.map((_, i) => (<button key={i} onClick={() => setCurrentIndex(i)} className={`h-2 transition-all rounded-full ${currentIndex === i ? 'w-8 bg-brand' : 'w-2 bg-white/10'}`} />))}</div><button disabled={currentIndex === carousel.slides.length - 1} onClick={() => setCurrentIndex(prev => prev + 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5"><ChevronRight size={20}/></button></div>)}
        </main>
      </div>
    </div>
  );
};

export default App;
